  // ===== STORAGE WITH MIGRATION =====

  class Storage {

    static get(key, defaultValue = null) {

      try {

        const stored = GM_getValue(key);

        if (stored === undefined) {

          return defaultValue;

        }

        if (typeof stored === 'string') {

          try {

            return JSON.parse(stored);

          } catch (e) {

            return stored;

          }

        }

        return stored;

      } catch (e) {

        return defaultValue;

      }

    }

    static set(key, value) {

      try {

        GM_setValue(

          key,

          typeof value === 'string'

            ? value

            : JSON.stringify(value)

        );

      } catch (e) {

        console.error('[Storage] set error', e);

      }

    }

    static clear(key) {

      try {

        GM_deleteValue(key);

      } catch (e) {

        console.error('[Storage] clear error', e);

      }

    }

    static migrate() {

      const currentSchema = Storage.get('bf_schemaVersion', 0);

      if (currentSchema >= SCHEMA_VERSION) {

        return;

      }

      console.log(

        `[Storage] Migrating from schema ${currentSchema} to ${SCHEMA_VERSION}`

      );

      // Migration from 0->1: Validate stats shape

      if (currentSchema < 1) {

        const stats = Storage.get('bf_stats', {});

        if (typeof stats.coinsWon !== 'number') {

          stats.coinsWon = 0;

        }

        if (typeof stats.boxesClaimed !== 'number') {

          stats.boxesClaimed = 0;

        }

        if (typeof stats.coindropsSniped !== 'number') {

          stats.coindropsSniped = 0;

        }

        Storage.set('bf_stats', stats);

      }

      // Migration from 1->2: Ensure positions are clamped

      if (currentSchema < 2) {

        const positions = Storage.get(

          'bf_spritePositions',

          {}

        );

        Object.keys(positions).forEach(key => {

          const pos = positions[key];

          if (

            typeof pos.x !== 'number' ||

            typeof pos.y !== 'number'

          ) {

            delete positions[key];

          } else {

            positions[key] = {

              x: Math.max(0, pos.x),

              y: Math.max(0, pos.y)

            };

          }

        });

        Storage.set(

          'bf_spritePositions',

          positions

        );

      }

      // Migration from 2->3: enrich stats and UI/event defaults

      if (currentSchema < 3) {

        const stats = {

          ...DEFAULTS.stats,

          ...(Storage.get('bf_stats', {}) || {})

        };

        if (!stats.sessionStart) {

          stats.sessionStart = Date.now();

        }

        Storage.set('bf_stats', stats);

        if (

          Storage.get('bf_debugMode', undefined) === undefined

        ) {

          Storage.set(

            'bf_debugMode',

            DEFAULTS.debugMode

          );

        }

        if (!Storage.get('bf_uiSettings', null)) {

          Storage.set(

            'bf_uiSettings',

            DEFAULTS.uiSettings

          );

        }

        if (!Storage.get('bf_visuals', null)) {

          Storage.set(

            'bf_visuals',

            DEFAULTS.visuals

          );

        }

      }

      Storage.set(

        'bf_schemaVersion',

        SCHEMA_VERSION

      );

    }

  }

