// ===== AUTO CLAIM =====
  class AutoClaim {
    constructor() {
      this.isRunning = false;
      this._timeoutId = null;
      this._lockKey = 'bf_lastTabOpenedAt';
      this.COOLDOWN =
        90 * 60 * 1000;
      this.disposables =
        new Disposables();
    }

    start() {
      if (this.isRunning) {
        return;
      }

      this.isRunning = true;

      settings.set(
        'autoClaimRunning',
        true
      );

      console.log(
        '[AutoClaim] Started'
      );

      const initialDelay =
        HumanBehavior.randomIdle(
          3000,
          8000
        );

      this.disposables.addTimeout(
        setTimeout(() => {
          this.performClaim({
            force: true
          });
        }, initialDelay)
      );
    }

    stop() {
      this.isRunning = false;

      settings.set(
        'autoClaimRunning',
        false
      );

      if (this._timeoutId) {
        clearTimeout(
          this._timeoutId
        );

        this._timeoutId = null;
      }
    }

    performClaim({
      force = false
    } = {}) {
      const lastTab =
        Storage.get(
          this._lockKey,
          0
        );

      const now = Date.now();

      const timeSinceLastTab =
        now - lastTab;

      if (
        !force &&
        lastTab > 0 &&
        timeSinceLastTab <
          this.COOLDOWN
      ) {
        const remainingMins =
          Math.ceil(
            (
              this.COOLDOWN -
              timeSinceLastTab
            ) / 60000
          );

        console.log(
          '[AutoClaim] BLOCKED - Wait ' +
          remainingMins +
          'm'
        );

        if (this._timeoutId) {
          clearTimeout(
            this._timeoutId
          );
        }

        const retryDelay =
          this.COOLDOWN -
          timeSinceLastTab +
          HumanBehavior
            .gaussianDelay(
              5000,
              0.5
            );

        this._timeoutId =
          this.disposables
            .addTimeout(
              setTimeout(() => {
                if (
                  this.isRunning
                ) {
                  this.performClaim();
                }
              }, retryDelay)
            );

        return;
      }

      console.log(
        '[AutoClaim] OPENING TAB'
      );

      Storage.set(
        this._lockKey,
        now
      );

      const claimUrl =
        window.location.origin +
        '/boxes/all?autoClaim=true#tfmClaimTab=1';

      const openDelay =
        Math.random() < 0.2
          ? HumanBehavior
              .gaussianDelay(
                2000,
                0.6
              )
          : HumanBehavior
              .gaussianDelay(
                500,
                0.3
              );

      this.disposables.addTimeout(
        setTimeout(() => {
          safeRun(() => {
            if (
              typeof GM_openInTab ===
              'function'
            ) {
              GM_openInTab(
                claimUrl,
                {
                  active: true,
                  insert: true,
                  setParent: true
                }
              );
            } else {
              window.open(
                claimUrl,
                '_blank'
              );
            }
          }, 'open-tab');
        }, openDelay)
      );

      if (this._timeoutId) {
        clearTimeout(
          this._timeoutId
        );
      }

      const variation =
        this.COOLDOWN *
        (
          0.9 +
          Math.random() *
          0.2
        );

      this._timeoutId =
        this.disposables
          .addTimeout(
            setTimeout(() => {
              if (
                this.isRunning
              ) {
                this.performClaim();
              }
            }, variation)
          );

      settings.set(
        'nextClaimTime',
        now + variation
      );
    }
  }

