  // Global/VIP tab orchestration removed; claim tabs remain supported.

  function fakeMouseMove(
    element
  ) {
    if (!element) {
      return;
    }

    const rect =
      element
        .getBoundingClientRect();

    const targetX =
      rect.left +
      rect.width / 2;

    const targetY =
      rect.top +
      rect.height / 2;

    const currentX =
      window.lastMouseX ||
      window.innerWidth / 2;

    const currentY =
      window.lastMouseY ||
      window.innerHeight / 2;

    const paths =
      HumanBehavior
        .curvedMousePath(
          currentX,
          currentY,
          targetX,
          targetY,
          300
        );

    paths.forEach(position => {
      setTimeout(() => {
        try {
          const event =
            new MouseEvent(
              'mousemove',
              {
                bubbles: true,
                cancelable: true,
                clientX:
                  position.x,
                clientY:
                  position.y
              }
            );

          element.dispatchEvent(
            event
          );

          window.lastMouseX =
            position.x;

          window.lastMouseY =
            position.y;
        } catch (error) {}
      }, position.delay);
    });
  }

