  // ==========================================================
  // EVENT MANAGER
  // ==========================================================

  class EventManager {
    constructor() {
      this.events = new Map();
    }

    on(eventName, callback) {
      if (
        typeof eventName !== 'string' ||
        typeof callback !== 'function'
      ) {
        return () => {};
      }

      if (!this.events.has(eventName)) {
        this.events.set(
          eventName,
          new Set()
        );
      }

      const listeners =
        this.events.get(eventName);

      listeners.add(callback);

      return () => {
        this.off(
          eventName,
          callback
        );
      };
    }

    once(eventName, callback) {
      const unsubscribe =
        this.on(
          eventName,
          payload => {
            unsubscribe();
            callback(payload);
          }
        );

      return unsubscribe;
    }

    off(eventName, callback) {
      const listeners =
        this.events.get(eventName);

      if (!listeners) {
        return;
      }

      listeners.delete(callback);

      if (listeners.size === 0) {
        this.events.delete(
          eventName
        );
      }
    }

    emit(eventName, payload = {}) {
      const listeners =
        this.events.get(eventName);

      if (!listeners) {
        return;
      }

      [...listeners].forEach(
        callback => {
          try {
            callback(payload);
          } catch (error) {
            console.warn(
              '[TheFreshMaker Event Error]',
              eventName,
              error
            );
          }
        }
      );
    }

    clear(eventName = null) {
      if (eventName) {
        this.events.delete(
          eventName
        );

        return;
      }

      this.events.clear();
    }

    listenerCount(eventName) {
      return (
        this.events.get(eventName)
          ?.size || 0
      );
    }
  }

  const eventManager =
    new EventManager();

  // ==========================================================
  // DEBUG LOGGER
  // ==========================================================

  class DebugLogger {
    constructor(limit = 400) {
      this.limit = limit;
      this.entries = [];
    }

    add(
      type,
      message,
      data = null
    ) {
      const entry = {
        timestamp: Date.now(),
        isoTime:
          new Date().toISOString(),
        type,
        message,
        data
      };

      this.entries.push(entry);

      if (
        this.entries.length >
        this.limit
      ) {
        this.entries.splice(
          0,
          this.entries.length -
            this.limit
        );
      }

      if (
        settings.get(
          'debugMode'
        ) !== false
      ) {
        console.log(
          `[TheFreshMaker ${type}] ${message}`,
          data ?? ''
        );
      }

      return entry;
    }

    info(message, data = null) {
      return this.add(
        'INFO',
        message,
        data
      );
    }

    warn(message, data = null) {
      return this.add(
        'WARN',
        message,
        data
      );
    }

    error(message, data = null) {
      return this.add(
        'ERROR',
        message,
        data
      );
    }

    get(limit = this.limit) {
      return this.entries.slice(
        -Math.max(1, limit)
      );
    }

    clear() {
      this.entries.length = 0;
    }

    exportText() {
      return JSON.stringify(
        this.entries,
        null,
        2
      );
    }
  }

