  // ==========================================================
  // LIVE HUD
  // ==========================================================

  class LiveHUD {
    constructor() {
      this.element = null;
      this.statusElement = null;
      this.metaElement = null;
      this.disposables =
        new Disposables();

      if (window.TFM_PILL_ONLY_MODE) return;

      this.create();
      this.bind();
    }

    create() {
      const existing =
        document.getElementById(
          'tfm-live-hud'
        );

      if (existing) {
        existing.remove();
      }

      const hud =
        document.createElement(
          'div'
        );

      hud.id =
        'tfm-live-hud';

      hud.innerHTML = `
        <div id="tfm-live-hud-header">
          <span id="tfm-live-hud-title">
            TheFreshMaker
          </span>

          <span style="display:flex;align-items:center;gap:8px;">
            <span id="tfm-live-hud-version">
              v${extension.version}
            </span>

            <button
              id="tfm-live-hud-minimize"
              class="tfm-panel-minimize"
              type="button"
              aria-label="Minimize runtime log"
            >−</button>
          </span>
        </div>

        <div id="tfm-live-hud-status">
          🟡 Initialising
        </div>

        <div id="tfm-live-hud-meta">
          profile: ${
            settings.get('profile') ||
            'normal'
          }
        </div>
      `;

      document.body
        .appendChild(hud);

      this.element =
        hud;

      this.statusElement =
        hud.querySelector(
          '#tfm-live-hud-status'
        );

      this.metaElement =
        hud.querySelector(
          '#tfm-live-hud-meta'
        );

      hud.querySelector(
        '#tfm-live-hud-minimize'
      )?.addEventListener(
        'click',
        event => {
          event.stopPropagation();
          this.toggleMinimized();
        }
      );

      this.applyMinimizedState();

      this.updateVisibility();

      this.disposables
        .addInterval(
          setInterval(() => {
            this.refreshMeta();
          }, 1000)
        );
    }

    applyMinimizedState() {
      if (!this.element) {
        return;
      }

      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      const minimized =
        ui.liveHudMinimized ===
        true;

      this.element.classList.toggle(
        'tfm-minimized',
        minimized
      );

      const button =
        this.element.querySelector(
          '#tfm-live-hud-minimize'
        );

      if (button) {
        button.textContent =
          minimized ? '+' : '−';

        button.setAttribute(
          'aria-label',
          minimized
            ? 'Restore runtime log'
            : 'Minimize runtime log'
        );
      }
    }

    toggleMinimized() {
      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      settings.set(
        'uiSettings',
        {
          ...ui,
          liveHudMinimized:
            !ui.liveHudMinimized
        }
      );

      this.applyMinimizedState();
    }

    updateVisibility() {
      if (!this.element) {
        return;
      }

      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      this.element
        .classList
        .toggle(
          'tfm-hidden',
          ui.showStatus === false
        );
    }

    setStatus(
      text,
      type = 'default'
    ) {
      if (
        !this.statusElement
      ) {
        return;
      }

      this.statusElement
        .textContent =
        text;

      const colours = {
        default: '#ffffff',
        success: '#a9ffd2',
        warning: '#ffe4a8',
        error: '#ffc4c4',
        info: '#c8f7ff'
      };

      this.statusElement
        .style.color =
        colours[type] ||
        colours.default;
    }

    refreshMeta() {
      if (
        !this.metaElement
      ) {
        return;
      }

      const stats =
        statsManager
          .getStats();

      const profile =
        settings.get(
          'profile'
        ) || 'normal';

      const health =
        extension.sniper
          ?.health?.() || {};

      const reaction =
        stats.lastReaction ===
          null
          ? '-'
          : stats.lastReaction +
            'ms';

      this.metaElement
        .textContent =
        `profile: ${profile} • state: ${
          health.state ||
          'unknown'
        } • last: ${reaction}`;

      this.updateVisibility();
    }

    bind() {
      eventManager.on(
        'SNIPER_ARMED',
        () => {
          this.setStatus(
            '🟢 Sniper armed',
            'success'
          );
        }
      );

      eventManager.on(
        'DROP_FOUND',
        event => {
          this.setStatus(
            `🎯 Drop found • ${event.detectionMethod}`,
            'info'
          );
        }
      );

      eventManager.on(
        'CLAIM_SCHEDULED',
        event => {
          this.setStatus(
            `⏳ Claiming in ${event.delay}ms`,
            'warning'
          );
        }
      );

      eventManager.on(
        'CLAIM_START',
        () => {
          this.setStatus(
            '⚔️ Claiming drop',
            'info'
          );
        }
      );

      eventManager.on(
        'CLAIM_RETRY',
        () => {
          this.setStatus(
            '🔄 Retrying claim',
            'warning'
          );
        }
      );

      eventManager.on(
        'CLAIM_SUCCESS',
        event => {
          this.setStatus(
            `🏆 Claimed in ${event.reaction}ms`,
            'success'
          );
        }
      );

      eventManager.on(
        'CLAIM_FAIL',
        event => {
          this.setStatus(
            `❌ Claim failed • ${event.reason}`,
            'error'
          );
        }
      );

      eventManager.on(
        'WATCHDOG_RESET',
        () => {
          this.setStatus(
            '⚠️ Watchdog recovered',
            'warning'
          );
        }
      );

      eventManager.on(
        'PROFILE_CHANGED',
        event => {
          this.setStatus(
            `⚙️ Profile: ${event.profile}`,
            'info'
          );
        }
      );

      eventManager.on(
        'SNIPER_TOGGLED',
        event => {
          this.setStatus(
            event.enabled
              ? '🟢 Sniper enabled'
              : '🔴 Sniper disabled',
            event.enabled
              ? 'success'
              : 'error'
          );
        }
      );
    }

    destroy() {
      this.disposables.clear();

      if (
        this.element &&
        this.element.parentNode
      ) {
        this.element.remove();
      }

      this.element = null;
    }
  }

  // ==========================================================
  // EVENT TOASTS
  // ==========================================================

  class EventToastManager {
    constructor() {
      this.container = null;
      this.active =
        new Set();

      if (window.TFM_PILL_ONLY_MODE) return;

      this.createContainer();
      this.bind();
    }

    createContainer() {
      const existing =
        document.getElementById(
          'tfm-event-toast-container'
        );

      if (existing) {
        this.container =
          existing;

        return;
      }

      const container =
        document.createElement(
          'div'
        );

      container.id =
        'tfm-event-toast-container';

      container.style.display =
        'none';

      document.body
        .appendChild(container);

      this.container =
        container;
    }

    show(
      message,
      duration = 1400,
      type = 'info'
    ) {
      if (window.TFM_PILL_ONLY_MODE) return;

      if (!this.container) {
        this.createContainer();
      }

      const toast =
        document.createElement(
          'div'
        );

      toast.className =
        `tfm-event-toast tfm-${type}`;

      toast.textContent =
        message;

      this.container
        .appendChild(toast);

      this.active.add(toast);

      requestAnimationFrame(() => {
        toast.classList
          .add(
            'tfm-visible'
          );
      });

      setTimeout(() => {
        toast.classList
          .remove(
            'tfm-visible'
          );

        setTimeout(() => {
          this.active.delete(
            toast
          );

          if (
            toast.parentNode
          ) {
            toast.remove();
          }
        }, 250);
      }, duration);

      return toast;
    }

    bind() {
      eventManager.on(
        'DROP_FOUND',
        event => {
          this.show(
            `🎯 COINDROP DETECTED • ${event.detectionMethod}`,
            1200,
            'info'
          );
        }
      );

      eventManager.on(
        'CLAIM_RETRY',
        () => {
          this.show(
            '🔄 SECOND SHOT',
            900,
            'warning'
          );
        }
      );

      eventManager.on(
        'CLAIM_SUCCESS',
        event => {
          this.show(
            `🏆 CLAIMED IN ${event.reaction}ms`,
            1800,
            'success'
          );
        }
      );

      eventManager.on(
        'CLAIM_FAIL',
        event => {
          this.show(
            `❌ MISSED • ${event.reason}`,
            1400,
            'error'
          );
        }
      );

      eventManager.on(
        'WATCHDOG_RESET',
        () => {
          this.show(
            '⚠️ SNIPER RECOVERED',
            1300,
            'warning'
          );
        }
      );

      eventManager.on(
        'THANK_YOU_SENT',
        event => {
          this.show(
            `💬 ${event.message}`,
            1200,
            'info'
          );
        }
      );

      eventManager.on(
        'PROFILE_CHANGED',
        event => {
          this.show(
            `⚙️ PROFILE: ${String(
              event.profile
            ).toUpperCase()}`,
            900,
            'info'
          );
        }
      );
    }

    clear() {
      this.active
        .forEach(toast => {
          if (
            toast.parentNode
          ) {
            toast.remove();
          }
        });

      this.active.clear();
    }
  }

