  class StatsDashboard {
    constructor() {
      this.element = null;
      this.disposables =
        new Disposables();

      if (window.TFM_PILL_ONLY_MODE) return;

      this.create();
      this.bind();
    }

    create() {
      const existing =
        document.getElementById(
          'tfm-stats-panel'
        );

      if (existing) {
        existing.remove();
      }

      const panel =
        document.createElement(
          'div'
        );

      panel.id =
        'tfm-stats-panel';

      panel.innerHTML = `
        <div id="tfm-stats-title">
          <span>LIVE STATS</span>

          <button
            id="tfm-stats-minimize"
            class="tfm-panel-minimize"
            type="button"
            aria-label="Minimize live stats"
          >−</button>
        </div>

        <div id="tfm-stats-grid"></div>
      `;

      document.body
        .appendChild(panel);

      this.element =
        panel;

      panel.querySelector(
        '#tfm-stats-minimize'
      )?.addEventListener(
        'click',
        event => {
          event.stopPropagation();
          this.toggleMinimized();
        }
      );

      this.applyMinimizedState();

      this.render();

      this.disposables
        .addInterval(
          setInterval(() => {
            this.render();
          }, 1500)
        );
    }

    applyMinimizedState() {
      if (!this.element) {
        return;
      }

      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      const minimized =
        ui.statsMinimized ===
        true;

      this.element.classList.toggle(
        'tfm-minimized',
        minimized
      );

      const button =
        this.element.querySelector(
          '#tfm-stats-minimize'
        );

      if (button) {
        button.textContent =
          minimized ? '+' : '−';

        button.setAttribute(
          'aria-label',
          minimized
            ? 'Restore live stats'
            : 'Minimize live stats'
        );
      }
    }

    toggleMinimized() {
      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      settings.set(
        'uiSettings',
        {
          ...ui,
          statsMinimized:
            !ui.statsMinimized
        }
      );

      this.applyMinimizedState();
    }

    formatValue(
      value,
      suffix = ''
    ) {
      if (
        value === null ||
        value === undefined
      ) {
        return '-';
      }

      return String(value) +
        suffix;
    }

    render() {
      if (!this.element) {
        return;
      }

      const ui =
        settings.get(
          'uiSettings'
        ) || {};

      this.element
        .classList
        .toggle(
          'tfm-hidden',
          ui.showStats === false
        );

      const grid =
        this.element
          .querySelector(
            '#tfm-stats-grid'
          );

      if (!grid) {
        return;
      }

      const stats =
        statsManager
          .getStats();

      const sessionMinutes =
        Math.floor(
          (
            Date.now() -
            stats.sessionStart
          ) /
          60000
        );

      const items = [
        [
          stats.successfulClaims,
          'Claims'
        ],
        [
          stats.failedAttempts,
          'Failed'
        ],
        [
          this.formatValue(
            stats.fastestClaim,
            stats.fastestClaim ===
              null
              ? ''
              : 'ms'
          ),
          'Fastest'
        ],
        [
          this.formatValue(
            stats.averageReaction,
            stats.averageReaction
              ? 'ms'
              : ''
          ),
          'Average'
        ],
        [
          stats.currentStreak,
          'Streak'
        ],
        [
          sessionMinutes + 'm',
          'Session'
        ]
      ];

      grid.innerHTML =
        '';

      items.forEach(
        ([value, label]) => {
          const card =
            document.createElement(
              'div'
            );

          card.className =
            'tfm-stat-card';

          card.innerHTML = `
            <span class="tfm-stat-number">
              ${value}
            </span>

            <span class="tfm-stat-label">
              ${label}
            </span>
          `;

          grid.appendChild(
            card
          );
        }
      );
    }

    bind() {
      eventManager.on(
        'STATS_UPDATED',
        () => {
          this.render();
        }
      );
    }

    destroy() {
      this.disposables.clear();

      if (
        this.element &&
        this.element.parentNode
      ) {
        this.element.remove();
      }

      this.element = null;
    }
  }

  // ==========================================================
  // COIN SCENE
  // ==========================================================

  class CoinSceneManager {
    constructor() {
      this.element = null;
      this.label = null;
      this.hideTimer = null;

      this.create();
    }

    create() {
      const existing =
        document.getElementById(
          'tfm-coin-scene'
        );

      if (existing) {
        existing.remove();
      }

      const scene =
        document.createElement(
          'div'
        );

      scene.id =
        'tfm-coin-scene';

      scene.innerHTML = `
        <div id="tfm-coin-scene-ring"></div>

        <div id="tfm-coin-scene-coin">
          🪙
        </div>

        <div id="tfm-coin-scene-label">
          COINDROP
        </div>
      `;

      document.body
        .appendChild(scene);

      this.element =
        scene;

      this.label =
        scene.querySelector(
          '#tfm-coin-scene-label'
        );
    }

    shouldShow() {
      const visuals =
        settings.get(
          'visuals'
        ) || {};

      return (
        visuals.enabled !==
          false &&
        visuals.coinScene !==
          false
      );
    }

    show(
      label = 'COINDROP'
    ) {
      if (
        !this.shouldShow()
      ) {
        return;
      }

      if (
        !this.element ||
        !isElementConnected(
          this.element
        )
      ) {
        this.create();
      }

      if (this.label) {
        this.label.textContent =
          label;
      }

      this.element
        .classList
        .add(
          'tfm-visible'
        );

      if (this.hideTimer) {
        clearTimeout(
          this.hideTimer
        );
      }
    }

    hide(
      delay = 450
    ) {
      if (this.hideTimer) {
        clearTimeout(
          this.hideTimer
        );
      }

      this.hideTimer =
        setTimeout(() => {
          this.element
            ?.classList
            .remove(
              'tfm-visible'
            );
        }, delay);
    }

    found() {
      this.show(
        'DROP FOUND'
      );
    }

    grab() {
      this.show(
        'CLAIMING'
      );
    }

    win() {
      this.show(
        'CLAIMED!'
      );

      this.hide(
        1100
      );
    }

    fail() {
      this.show(
        'MISSED'
      );

      this.hide(
        800
      );
    }
  }

  // ==========================================================
  // SPRITE REACTIONS
  // ==========================================================

  class SpriteReactionManager {
    constructor() {
      this.lastReactionAt =
        0;
    }

    getSprites() {
      return Array.from(
        document.querySelectorAll(
          'img[data-sprite-key]'
        )
      );
    }

    shouldReact() {
      // User-selected stationary mode keeps the GIF's own frames playing,
      // but disables scripted hops, attacks and position reactions.
      return false;
    }

    clearReactionClasses(
      sprite
    ) {
      [
        'tfm-sprite-alert',
        'tfm-sprite-attack',
        'tfm-sprite-victory',
        'tfm-sprite-fail',
        'tfm-sprite-rival'
      ].forEach(
        className => {
          sprite.classList
            .remove(
              className
            );
        }
      );
    }

    react(
      reaction
    ) {
      if (
        !this.shouldReact()
      ) {
        return;
      }

      core.spriteManager?.pauseAll?.(1350);

      const sprites =
        this.getSprites();

      if (
        sprites.length === 0
      ) {
        return;
      }

      const classMap = {
        alert:
          'tfm-sprite-alert',
        attack:
          'tfm-sprite-attack',
        victory:
          'tfm-sprite-victory',
        fail:
          'tfm-sprite-fail',
        rival:
          'tfm-sprite-rival'
      };

      const className =
        classMap[reaction];

      if (!className) {
        return;
      }

      sprites.forEach(
        (sprite, index) => {
          this.clearReactionClasses(
            sprite
          );

          setTimeout(() => {
            void sprite.offsetWidth;

            sprite.classList
              .add(
                className
              );

            setTimeout(() => {
              sprite.classList
                .remove(
                  className
                );
            }, 1100);
          }, index * 55);
        }
      );

      this.lastReactionAt =
        Date.now();
    }
  }

  // ==========================================================
  // SCREEN FLASH
  // ==========================================================

  function flashScreen() {
    const visuals =
      settings.get(
        'visuals'
      ) || {};

    if (
      visuals.enabled ===
        false ||
      visuals.screenFlash ===
        false
    ) {
      return;
    }

    const root =
      document.documentElement;

    root.classList
      .remove(
        'tfm-screen-flash'
      );

    void root.offsetWidth;

    root.classList
      .add(
        'tfm-screen-flash'
      );

    setTimeout(() => {
      root.classList
        .remove(
          'tfm-screen-flash'
        );
    }, 380);
  }

  // ==========================================================
  // REACTION MANAGER
  // ==========================================================

  class ReactionManager {
    constructor(
      liveHUD,
      toastManager,
      statsDashboard,
      coinScene,
      spriteReactions
    ) {
      this.liveHUD =
        liveHUD;

      this.toastManager =
        toastManager;

      this.statsDashboard =
        statsDashboard;

      this.coinScene =
        coinScene;

      this.spriteReactions =
        spriteReactions;

      this.bind();
    }

    bind() {
      eventManager.on(
        'DROP_FOUND',
        event => {
          this.coinScene
            .found();

          this.spriteReactions
            .react(
              'alert'
            );

          flashScreen();

          debugLogger.info(
            'Visual DROP_FOUND reaction.',
            event
          );
        }
      );

      eventManager.on(
        'CLAIM_START',
        event => {
          this.coinScene
            .grab();

          this.spriteReactions
            .react(
              'attack'
            );

          core.spriteManager
            ?.rushToElement?.(
              event?.button,
              760
            );

          core.audioManager
            ?.play?.(
              'drop'
            );
        }
      );

      eventManager.on(
        'CLAIM_RETRY',
        () => {
          this.spriteReactions
            .react(
              'rival'
            );
        }
      );

      eventManager.on(
        'CLAIM_SUCCESS',
        () => {
          this.coinScene
            .win();

          this.spriteReactions
            .react(
              'victory'
            );

          const visuals =
            settings.get(
              'visuals'
            ) || {};

          if (
            visuals.enabled !==
              false &&
            visuals.particles !==
              false
          ) {
            core.Effects
              ?.showFireworks?.();
          }

          core.audioManager
            ?.play?.(
              'ty'
            );

          flashScreen();
        }
      );

      eventManager.on(
        'CLAIM_FAIL',
        () => {
          this.coinScene
            .fail();

          this.spriteReactions
            .react(
              'fail'
            );
        }
      );

      eventManager.on(
        'WATCHDOG_RESET',
        () => {
          this.coinScene
            .hide(
              200
            );

          this.spriteReactions
            .react(
              'fail'
            );
        }
      );
    }
  }

