  // ==========================================================
  // SETTINGS BACKUP MANAGER
  // ==========================================================

  class SettingsBackupManager {
    static buildPayload() {
      return {
        application:
          'TheFreshMaker',

        version:
          extension.version,

        exportedAt:
          new Date()
            .toISOString(),

        settings: {
          ...(settings.data || {})
        }
      };
    }

    static snapshot() {
      const payload =
        this.buildPayload();

      Storage.set(
        'bf_backup_latest',
        payload
      );

      return payload;
    }

    static exportText() {
      return JSON.stringify(
        this.snapshot(),
        null,
        2
      );
    }

    static validatePayload(
      payload
    ) {
      if (
        !payload ||
        typeof payload !==
          'object'
      ) {
        throw new Error(
          'Backup is not a valid object.'
        );
      }

      if (
        !payload.settings ||
        typeof payload.settings !==
          'object'
      ) {
        throw new Error(
          'Backup does not contain settings.'
        );
      }

      return true;
    }

    static importPayload(
      payload
    ) {
      this.validatePayload(
        payload
      );

      Object.entries(
        payload.settings
      ).forEach(
        ([key, value]) => {
          settings.set(
            key,
            value
          );
        }
      );

      this.snapshot();

      eventManager.emit(
        'SETTINGS_IMPORTED',
        {
          version:
            payload.version ||
            'unknown'
        }
      );

      return true;
    }

    static importText(
      text
    ) {
      const payload =
        JSON.parse(text);

      return this.importPayload(
        payload
      );
    }

    static recoverLatest() {
      const payload =
        Storage.get(
          'bf_backup_latest',
          null
        );

      if (!payload) {
        return false;
      }

      this.importPayload(
        payload
      );

      eventManager.emit(
        'SETTINGS_RECOVERED'
      );

      return true;
    }

    static download() {
      const text =
        this.exportText();

      const blob =
        new Blob(
          [text],
          {
            type:
              'application/json'
          }
        );

      const url =
        URL.createObjectURL(
          blob
        );

      const anchor =
        document.createElement(
          'a'
        );

      anchor.href = url;

      anchor.download =
        'TheFreshMaker-' +
        extension.version +
        '-settings.json';

      document.body
        .appendChild(anchor);

      anchor.click();

      anchor.remove();

      setTimeout(() => {
        URL.revokeObjectURL(
          url
        );
      }, 1000);
    }
  }

  // ==========================================================
  // HEALTH MONITOR
  // ==========================================================

  class HealthMonitor {
    constructor() {
      this.disposables =
        new Disposables();

      this.lastHealth =
        null;

      this.failureCount =
        0;

      this.start();
    }

    inspect() {
      const sniperHealth =
        sniper?.health?.() ||
        {};

      const pillExists =
        Boolean(
          document.getElementById(
            'bf-pill'
          )
        );

      const hudExists =
        Boolean(
          document.getElementById(
            'tfm-live-hud'
          )
        );

      const bodyReady =
        Boolean(
          document.body
        );

      const healthy =
        bodyReady &&
        sniperHealth
          .observerAttached !==
          false;

      return {
        healthy,

        timestamp:
          Date.now(),

        bodyReady,

        pillExists,

        hudExists,

        sniper:
          sniperHealth,

        profile:
          settings.get(
            'profile'
          ),

        sniperEnabled:
          settings.get(
            'sniperEnabled'
          ),

        autoClaimRunning:
          settings.get(
            'autoClaimRunning'
          )
      };
    }

    start() {
      this.disposables
        .addInterval(
          setInterval(() => {
            const health =
              this.inspect();

            this.lastHealth =
              health;

            if (!health.healthy) {
              this.failureCount += 1;

              debugLogger.warn(
                'Health monitor detected an unhealthy state.',
                health
              );

              eventManager.emit(
                'HEALTH_WARNING',
                health
              );

              if (
                this.failureCount >=
                2
              ) {
                this.recover(
                  health
                );
              }
            } else {
              this.failureCount =
                0;
            }
          }, 5000)
        );
    }

    recover(
      health = null
    ) {
      const report =
        health ||
        this.inspect();

      try {
        sniper?.recover?.();

        if (
          !document
            .getElementById(
              'bf-pill'
            )
        ) {
          core.pillButton
            ?.recreate?.();
        }

        if (
          !document
            .getElementById(
              'tfm-live-hud'
            )
        ) {
          extension.liveHUD
            ?.create?.();
        }

        if (
          !document
            .getElementById(
              'tfm-stats-panel'
            )
        ) {
          extension
            .statsDashboard
            ?.create?.();
        }

        this.failureCount =
          0;

        eventManager.emit(
          'HEALTH_RECOVERED',
          {
            report
          }
        );

        debugLogger.info(
          'Health recovery completed.',
          report
        );

        return true;
      } catch (error) {
        debugLogger.error(
          'Health recovery failed.',
          error
        );

        return false;
      }
    }

    destroy() {
      this.disposables.clear();
    }
  }

