  if (!window.TFM_PILL_ONLY_MODE) injectAnalyticsStyles();

  // ==========================================================
  // ANALYTICS PANEL
  // ==========================================================

  class AnalyticsPanel {
    constructor(
      analyticsManager
    ) {
      this.analyticsManager =
        analyticsManager;

      this.element = null;
      this.backdrop = null;
      this.visible = false;

      this.disposables =
        new Disposables();

      if (window.TFM_PILL_ONLY_MODE) return;

      this.create();
      this.bindKeyboard();
    }

    createButton(
      text,
      className,
      handler
    ) {
      const button =
        document.createElement(
          'button'
        );

      button.className =
        'tfm-analytics-button ' +
        (
          className || ''
        );

      button.textContent =
        text;

      button.addEventListener(
        'click',
        handler
      );

      return button;
    }

    create() {
      document.getElementById(
        'tfm-analytics-panel'
      )?.remove();

      document.getElementById(
        'tfm-analytics-backdrop'
      )?.remove();

      const backdrop =
        document.createElement(
          'div'
        );

      backdrop.id =
        'tfm-analytics-backdrop';

      backdrop.addEventListener(
        'click',
        () => this.hide()
      );

      const panel =
        document.createElement(
          'div'
        );

      panel.id =
        'tfm-analytics-panel';

      const header =
        document.createElement(
          'div'
        );

      header.id =
        'tfm-analytics-header';

      const title =
        document.createElement(
          'div'
        );

      title.id =
        'tfm-analytics-title';

      title.textContent =
        '📊 TheFreshMaker Analytics';

      const close =
        document.createElement(
          'button'
        );

      close.id =
        'tfm-analytics-close';

      close.textContent =
        '✕';

      close.addEventListener(
        'click',
        () => this.hide()
      );

      header.appendChild(title);
      header.appendChild(close);

      const summary =
        document.createElement(
          'div'
        );

      summary.id =
        'tfm-analytics-summary';

      const histogramSection =
        document.createElement(
          'div'
        );

      histogramSection.className =
        'tfm-analytics-section';

      histogramSection.innerHTML = `
        <div class="tfm-analytics-heading">
          Reaction distribution
        </div>

        <div id="tfm-analytics-histogram"></div>
      `;

      const profileSection =
        document.createElement(
          'div'
        );

      profileSection.className =
        'tfm-analytics-section';

      profileSection.innerHTML = `
        <div class="tfm-analytics-heading">
          Profile performance
        </div>

        <div id="tfm-analytics-profiles"></div>
      `;

      const timelineSection =
        document.createElement(
          'div'
        );

      timelineSection.className =
        'tfm-analytics-section';

      timelineSection.innerHTML = `
        <div class="tfm-analytics-heading">
          Recent claims
        </div>

        <div id="tfm-analytics-timeline"></div>
      `;

      const controlsSection =
        document.createElement(
          'div'
        );

      controlsSection.className =
        'tfm-analytics-section';

      const buttons =
        document.createElement(
          'div'
        );

      buttons.className =
        'tfm-analytics-buttons';

      buttons.appendChild(
        this.createButton(
          'Export JSON',
          '',
          () => {
            downloadText(
              `TheFreshMaker-analytics-${Date.now()}.json`,
              this.analyticsManager
                .exportJson(),
              'application/json'
            );
          }
        )
      );

      buttons.appendChild(
        this.createButton(
          'Export CSV',
          'tfm-purple',
          () => {
            downloadText(
              `TheFreshMaker-claims-${Date.now()}.csv`,
              this.analyticsManager
                .exportCsv(),
              'text/csv'
            );
          }
        )
      );

      buttons.appendChild(
        this.createButton(
          'Create snapshot',
          'tfm-warning',
          () => {
            this.analyticsManager
              .createSnapshot();

            eventToast?.show(
              'Analytics snapshot created',
              1100,
              'success'
            );

            this.render();
          }
        )
      );

      buttons.appendChild(
        this.createButton(
          'Clear analytics',
          'tfm-danger',
          () => {
            if (
              !confirm(
                'Clear the entire claim analytics history?'
              )
            ) {
              return;
            }

            this.analyticsManager
              .clear();

            eventToast?.show(
              'Analytics cleared',
              1100,
              'success'
            );

            this.render();
          }
        )
      );

      controlsSection.appendChild(
        buttons
      );

      panel.appendChild(header);
      panel.appendChild(summary);
      panel.appendChild(
        histogramSection
      );
      panel.appendChild(
        profileSection
      );
      panel.appendChild(
        timelineSection
      );
      panel.appendChild(
        controlsSection
      );

      document.body
        .appendChild(
          backdrop
        );

      document.body
        .appendChild(
          panel
        );

      this.element =
        panel;

      this.backdrop =
        backdrop;

      this.render();
    }

    renderSummary(
      summary
    ) {
      const element =
        this.element
          ?.querySelector(
            '#tfm-analytics-summary'
          );

      if (!element) {
        return;
      }

      const values = [
        [
          summary.completedClaims,
          'Claims'
        ],
        [
          summary.successful,
          'Success'
        ],
        [
          summary.failed,
          'Failed'
        ],
        [
          summary.successRate +
            '%',
          'Success rate'
        ],
        [
          summary.averageReaction
            ? summary
                .averageReaction +
              'ms'
            : '-',
          'Average'
        ],
        [
          summary
            .medianReaction
            ? summary
                .medianReaction +
              'ms'
            : '-',
          'Median'
        ],
        [
          summary
            .fastestReaction !==
            null
            ? summary
                .fastestReaction +
              'ms'
            : '-',
          'Fastest'
        ],
        [
          summary.retries,
          'Retries'
        ]
      ];

      element.innerHTML =
        '';

      values.forEach(
        ([value, label]) => {
          const card =
            document.createElement(
              'div'
            );

          card.className =
            'tfm-analytics-card';

          card.innerHTML = `
            <span class="tfm-analytics-value">
              ${value}
            </span>

            <span class="tfm-analytics-label">
              ${label}
            </span>
          `;

          element.appendChild(
            card
          );
        }
      );
    }

    renderHistogram(
      histogram
    ) {
      const element =
        this.element
          ?.querySelector(
            '#tfm-analytics-histogram'
          );

      if (!element) {
        return;
      }

      element.innerHTML =
        '';

      const maximum =
        Math.max(
          1,
          ...Object.values(
            histogram
          )
        );

      Object.entries(
        histogram
      ).forEach(
        ([label, count]) => {
          const row =
            document.createElement(
              'div'
            );

          row.className =
            'tfm-histogram-row';

          const width =
            Math.max(
              1,
              Math.round(
                count /
                maximum *
                100
              )
            );

          row.innerHTML = `
            <span>${label}</span>

            <div class="tfm-histogram-bar-wrap">
              <div
                class="tfm-histogram-bar"
                style="width:${width}%"
              ></div>
            </div>

            <span>${count}</span>
          `;

          element.appendChild(
            row
          );
        }
      );
    }

    renderProfiles(
      profiles
    ) {
      const element =
        this.element
          ?.querySelector(
            '#tfm-analytics-profiles'
          );

      if (!element) {
        return;
      }

      const entries =
        Object.entries(
          profiles
        );

      if (
        entries.length === 0
      ) {
        element.textContent =
          'No profile data yet.';

        return;
      }

      const table =
        document.createElement(
          'table'
        );

      table.className =
        'tfm-analytics-table';

      table.innerHTML = `
        <thead>
          <tr>
            <th>Profile</th>
            <th>Total</th>
            <th>Success</th>
            <th>Failed</th>
            <th>Rate</th>
            <th>Average</th>
            <th>Fastest</th>
          </tr>
        </thead>
      `;

      const body =
        document.createElement(
          'tbody'
        );

      entries.forEach(
        ([profile, data]) => {
          const row =
            document.createElement(
              'tr'
            );

          row.innerHTML = `
            <td>${profile}</td>
            <td>${data.total}</td>
            <td class="tfm-analytics-success">
              ${data.success}
            </td>
            <td class="tfm-analytics-failure">
              ${data.failure}
            </td>
            <td>${data.successRate}%</td>
            <td>
              ${
                data.averageReaction
                  ? data.averageReaction +
                    'ms'
                  : '-'
              }
            </td>
            <td>
              ${
                data.fastestReaction !==
                null
                  ? data.fastestReaction +
                    'ms'
                  : '-'
              }
            </td>
          `;

          body.appendChild(
            row
          );
        }
      );

      table.appendChild(body);

      element.innerHTML =
        '';

      element.appendChild(
        table
      );
    }

    renderTimeline() {
      const element =
        this.element
          ?.querySelector(
            '#tfm-analytics-timeline'
          );

      if (!element) {
        return;
      }

      const records =
        this.analyticsManager
          .records
          .slice(-25)
          .reverse();

      if (
        records.length === 0
      ) {
        element.textContent =
          'No claim records yet.';

        return;
      }

      const table =
        document.createElement(
          'table'
        );

      table.className =
        'tfm-analytics-table';

      table.innerHTML = `
        <thead>
          <tr>
            <th>Time</th>
            <th>Result</th>
            <th>Reaction</th>
            <th>Profile</th>
            <th>Method</th>
            <th>Retry</th>
          </tr>
        </thead>
      `;

      const body =
        document.createElement(
          'tbody'
        );

      records.forEach(
        record => {
          const row =
            document.createElement(
              'tr'
            );

          const date =
            record.completedAt ||
            record.detectedAt;

          const time =
            date
              ? new Date(
                  date
                )
                  .toLocaleTimeString()
              : '-';

          const resultClass =
            record.result ===
              'success'
              ? 'tfm-analytics-success'
              : record.result ===
                  'failure'
                ? 'tfm-analytics-failure'
                : '';

          row.innerHTML = `
            <td>${time}</td>

            <td class="${resultClass}">
              ${record.result}
            </td>

            <td>
              ${
                record.reaction !==
                null
                  ? record.reaction +
                    'ms'
                  : '-'
              }
            </td>

            <td>
              ${record.profile || '-'}
            </td>

            <td>
              ${
                record
                  .detectionMethod ||
                '-'
              }
            </td>

            <td>
              ${
                record.retryUsed
                  ? 'Yes'
                  : 'No'
              }
            </td>
          `;

          body.appendChild(
            row
          );
        }
      );

      table.appendChild(body);

      element.innerHTML =
        '';

      element.appendChild(
        table
      );
    }

    render() {
      if (!this.element) {
        return;
      }

      const summary =
        this.analyticsManager
          .summary();

      this.renderSummary(
        summary
      );

      this.renderHistogram(
        summary.histogram
      );

      this.renderProfiles(
        summary.profileSummary
      );

      this.renderTimeline();
    }

    bindKeyboard() {
      this.disposables
        .addEventListener(
          document,
          'keydown',
          event => {
            if (
              event.shiftKey &&
              event.key
                .toLowerCase() ===
                'x'
            ) {
              event.preventDefault();

              this.toggle();
            }

            if (
              event.key ===
                'Escape' &&
              this.visible
            ) {
              this.hide();
            }
          }
        );
    }

    show() {
      if (!this.element) {
        this.create();
      }

      this.visible =
        true;

      this.element
        .classList
        .add(
          'tfm-visible'
        );

      this.backdrop
        ?.classList
        .add(
          'tfm-visible'
        );

      this.render();
    }

    hide() {
      this.visible =
        false;

      this.element
        ?.classList
        .remove(
          'tfm-visible'
        );

      this.backdrop
        ?.classList
        .remove(
          'tfm-visible'
        );
    }

    toggle() {
      if (this.visible) {
        this.hide();
      } else {
        this.show();
      }
    }

    destroy() {
      this.disposables.clear();

      this.element
        ?.remove();

      this.backdrop
        ?.remove();

      this.element =
        null;

      this.backdrop =
        null;
    }
  }

  // ==========================================================
  // INITIALISE
  // ==========================================================

  const analyticsManager =
    new AnalyticsManager();

  const analyticsPanel =
    new AnalyticsPanel(
      analyticsManager
    );

  extension.analyticsManager =
    analyticsManager;

  extension.analyticsPanel =
    analyticsPanel;

  core.analyticsManager =
    analyticsManager;

  core.analyticsPanel =
    analyticsPanel;

