  class PartValidator {
    static getFlag(
      part
    ) {
      return Boolean(
        window[
          `TFM_V4_PART_${part}_LOADED`
        ]
      );
    }

    static inspect() {
      const loaded = [];

      const missing = [];

      REQUIRED_PARTS.forEach(
        part => {
          if (
            this.getFlag(part)
          ) {
            loaded.push(part);
          } else {
            missing.push(part);
          }
        }
      );

      return {
        required:
          [...REQUIRED_PARTS],

        loaded,

        missing,

        complete:
          missing.length === 0
      };
    }
  }

