  // ==========================================================
  // DUPLICATE DBZ SCENE GUARD
  // ==========================================================

  class DuplicateSceneGuard {
    constructor() {
      this.installed =
        false;

      this.lastCalls =
        new Map();

      this.originalMethods =
        new Map();

      this.install();
    }

    shouldBlock(
      methodName
    ) {
      finalSettings =
        getFinalSettings();

      if (
        finalSettings
          .preventDuplicateScenes ===
        false
      ) {
        return false;
      }

      const windowMs =
        Math.max(
          50,
          Number(
            finalSettings
              .duplicateSceneWindowMs
          ) || 350
        );

      const now =
        Date.now();

      const last =
        this.lastCalls.get(
          methodName
        ) || 0;

      this.lastCalls.set(
        methodName,
        now
      );

      return (
        now - last <
        windowMs
      );
    }

    wrap(
      methodName
    ) {
      if (
        !dbzSceneManager ||
        typeof dbzSceneManager[
          methodName
        ] !== 'function'
      ) {
        return;
      }

      if (
        this.originalMethods.has(
          methodName
        )
      ) {
        return;
      }

      const original =
        dbzSceneManager[
          methodName
        ].bind(
          dbzSceneManager
        );

      this.originalMethods.set(
        methodName,
        original
      );

      dbzSceneManager[
        methodName
      ] =
        async (...args) => {
          if (
            this.shouldBlock(
              methodName
            )
          ) {
            debugLogger?.info?.(
              `Duplicate DBZ scene blocked: ${methodName}`
            );

            return false;
          }

          return original(
            ...args
          );
        };
    }

    install() {
      if (
        this.installed ||
        !dbzSceneManager
      ) {
        return;
      }

      [
        'playDropFound',
        'playClaimStart',
        'playFriezaInterruption',
        'playGokuVictory',
        'playBrolyFailure',
        'handleSuccess',
        'handleFailure'
      ].forEach(
        methodName => {
          this.wrap(
            methodName
          );
        }
      );

      this.installed =
        true;

      debugLogger?.info?.(
        'Duplicate DBZ scene guard installed.'
      );
    }

    restore() {
      this.originalMethods
        .forEach(
          (
            original,
            methodName
          ) => {
            dbzSceneManager[
              methodName
            ] = original;
          }
        );

      this.originalMethods
        .clear();

      this.lastCalls
        .clear();

      this.installed =
        false;
    }
  }

  // ==========================================================
  // FINAL RUNTIME AUDITOR
  // ==========================================================

  class FinalRuntimeAuditor {
    constructor() {
      this.lastReport =
        null;

      this.auditCount =
        0;

      this.disposables =
        new Disposables();

      this.start();
    }

    inspectModules() {
      return {
        core:
          Boolean(core),

        extension:
          Boolean(extension),

        eventManager:
          Boolean(eventManager),

        sniper:
          Boolean(sniper),

        statsManager:
          Boolean(statsManager),

        healthMonitor:
          Boolean(healthMonitor),

        runtimeCoordinator:
          Boolean(
            runtimeCoordinator
          ),

        liveHUD:
          Boolean(liveHUD),

        settingsPanel:
          Boolean(settingsPanel),

        analytics:
          Boolean(
            analyticsManager
          ),

        integrity:
          Boolean(
            integrityTester
          ),

        dbzScene:
          Boolean(
            dbzSceneManager
          ),

        dbzQueue:
          Boolean(
            dbzSceneQueue
          ),

        dbzEffects:
          Boolean(
            dbzEffectLayer
          )
      };
    }

    inspectUi() {
      return {
        pill:
          Boolean(
            document.getElementById(
              'bf-pill'
            )
          ),

        hud:
          Boolean(
            document.getElementById(
              'tfm-live-hud'
            )
          ),

        stats:
          Boolean(
            document.getElementById(
              'tfm-stats-panel'
            )
          ),

        settings:
          Boolean(
            document.getElementById(
              'tfm-settings-panel'
            )
          )
      };
    }

    inspect() {
      const parts =
        PartValidator.inspect();

      const modules =
        this.inspectModules();

      const ui =
        this.inspectUi();

      const sniperHealth =
        safeCall(
          () =>
            sniper?.health?.(),
          null,
          'sniper health inspection'
        );

      const systemHealth =
        safeCall(
          () =>
            healthMonitor
              ?.inspect?.(),
          null,
          'system health inspection'
        );

      const missingModules =
        Object.entries(
          modules
        )
          .filter(
            ([, available]) =>
              !available
          )
          .map(
            ([name]) =>
              name
          );

      const report = {
        timestamp:
          Date.now(),

        isoTime:
          new Date()
            .toISOString(),

        version:
          FINAL_VERSION,

        build:
          BUILD_NAME,

        parts,

        modules,

        ui,

        sniper:
          sniperHealth,

        health:
          systemHealth,

        missingModules,

        healthy:
          parts.complete &&
          modules.core &&
          modules.extension &&
          modules.eventManager &&
          modules.sniper &&
          (
            sniperHealth
              ?.state !==
            'DESTROYED'
          )
      };

      this.lastReport =
        report;

      this.auditCount +=
        1;

      Storage.set(
        'bf_v4FinalAudit',
        report
      );

      eventManager?.emit?.(
        'FINAL_AUDIT_COMPLETED',
        {
          report
        }
      );

      return report;
    }

    repairUi() {
      finalSettings =
        getFinalSettings();

      if (
        finalSettings
          .automaticallyRepairUi ===
        false
      ) {
        return;
      }

      const ui =
        this.inspectUi();

      if (!ui.pill) {
        core.pillButton
          ?.recreate?.();
      }

      if (!ui.hud) {
        liveHUD
          ?.create?.();
      }

      if (!ui.stats) {
        statsDashboard
          ?.create?.();
      }
    }

    repairSniper() {
      finalSettings =
        getFinalSettings();

      if (
        finalSettings
          .automaticallyRepairSniper ===
        false
      ) {
        return;
      }

      const health =
        safeCall(
          () =>
            sniper?.health?.(),
          null,
          'sniper repair inspection'
        );

      if (
        settings.get(
          'sniperEnabled'
        ) &&
        (
          !health ||
          health.state ===
            'DESTROYED' ||
          health.observerAttached ===
            false
        )
      ) {
        sniper
          ?.recover?.();
      }
    }

    async auditAndRepair(
      reason = 'scheduled'
    ) {
      let report =
        this.inspect();

      if (!report.healthy) {
        debugLogger?.warn?.(
          'Final runtime audit found an issue.',
          {
            reason,
            report
          }
        );

        this.repairUi();

        this.repairSniper();

        healthMonitor
          ?.recover?.();

        await wait(250);

        report =
          this.inspect();
      }

      return report;
    }

    start() {
      const interval =
        Math.max(
          5000,
          Number(
            getFinalSettings()
              .runtimeAuditIntervalMs
          ) || 15000
        );

      this.disposables
        .addInterval(
          setInterval(() => {
            this.auditAndRepair(
              'scheduled'
            );
          }, interval)
        );

      eventManager?.on?.(
        'WATCHDOG_RESET',
        () => {
          this.auditAndRepair(
            'watchdog'
          );
        }
      );

      eventManager?.on?.(
        'HEALTH_WARNING',
        () => {
          this.auditAndRepair(
            'health-warning'
          );
        }
      );

      eventManager?.on?.(
        'V4_DESTROYED',
        () => {
          this.destroy();
        }
      );
    }

    destroy() {
      this.disposables
        .clear();
    }
  }

  // ==========================================================
  // FINAL STARTUP COORDINATOR
  // ==========================================================

  class FinalStartupCoordinator {
    constructor(
      auditor
    ) {
      this.auditor =
        auditor;

      this.started =
        false;

      this.completed =
        false;

      this.startedAt =
        null;

      this.completedAt =
        null;

      this.report =
        null;
    }

    async run() {
      if (this.started) {
        return this.report;
      }

      this.started =
        true;

      this.startedAt =
        Date.now();

      finalSettings =
        getFinalSettings();

      debugLogger?.info?.(
        `${BUILD_NAME} final startup beginning.`
      );

      const partReport =
        PartValidator.inspect();

      if (
        !partReport.complete
      ) {
        debugLogger?.warn?.(
          'One or more v4 parts are missing.',
          partReport
        );

        liveHUD?.setStatus?.(
          `⚠️ Missing parts: ${partReport.missing.join(', ')}`,
          'warning'
        );

        eventToast?.show?.(
          `Missing part(s): ${partReport.missing.join(', ')}`,
          2600,
          'warning'
        );
      }

      if (
        finalSettings
          .startupRecovery !==
        false
      ) {
        safeCall(
          () =>
            healthMonitor
              ?.recover?.(),
          null,
          'startup health recovery'
        );

        safeCall(
          () =>
            sniper
              ?.recover?.(),
          null,
          'startup sniper recovery'
        );
      }

      await wait(350);

      const audit =
        await this.auditor
          .auditAndRepair(
            'final-startup'
          );

      let integrity =
        null;

      if (
        finalSettings
          .startupValidation !==
          false &&
        integrityTester
          ?.run
      ) {
        integrity =
          await safeCallAsync(
            () =>
              integrityTester.run(
                'final-startup'
              ),
            null,
            'startup integrity validation'
          );
      }

      const healthy =
        Boolean(
          audit?.healthy &&
          (
            !integrity ||
            integrity.healthy !==
              false
          )
        );

      this.completed =
        true;

      this.completedAt =
        Date.now();

      this.report = {
        build:
          BUILD_NAME,

        version:
          FINAL_VERSION,

        startedAt:
          this.startedAt,

        completedAt:
          this.completedAt,

        duration:
          this.completedAt -
          this.startedAt,

        parts:
          partReport,

        audit,

        integrity,

        healthy
      };

      Storage.set(
        'bf_v4FinalStartupReport',
        this.report
      );

      Storage.set(
        'bf_v4BuildComplete',
        true
      );

      Storage.set(
        'bf_v4BuildVersion',
        FINAL_VERSION
      );

      Storage.set(
        'bf_v4BuildCompletedAt',
        Date.now()
      );

      if (healthy) {
        liveHUD?.setStatus?.(
          '🟢 barraisgay v4 ready',
          'success'
        );

        if (
          finalSettings
            .startupToast !==
          false
        ) {
          eventToast?.show?.(
            '✅ BARRAISGAY v4 READY',
            2200,
            'success'
          );
        }
      } else {
        liveHUD?.setStatus?.(
          '⚠️ v4 loaded with warnings',
          'warning'
        );

        if (
          finalSettings
            .startupToast !==
          false
        ) {
          eventToast?.show?.(
            '⚠️ v4 loaded with warnings',
            2400,
            'warning'
          );
        }
      }

      eventManager?.emit?.(
        'THEFRESHMAKER_V4_COMPLETE',
        {
          report:
            cloneValue(
              this.report
            )
        }
      );

      debugLogger?.info?.(
        `${BUILD_NAME} startup complete.`,
        this.report
      );

      return this.report;
    }
  }

